#include <stdlib.h>
#include <stdint.h>

static const int MOD = 998244353;

int64_t mod_pow(int64_t a, int64_t e, int64_t mod) {
    int64_t r = 1;
    while (e) {
        if (e & 1) r = r * a % mod;
        a = a * a % mod;
        e >>= 1;
    }
    return r;
}

